import org.w3c.dom.*;
import javax.xml.XMLConstants;

public class JXPathDomPointerExample {
   public static void main(String[] args) throws Exception {
       DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
       DocumentBuilder builder = factory.newDocumentBuilder();
       Document document = builder.parse("input.xml");
       XPathExpression expression = XPathFactory.newInstance().newXPath().compile("/root[1]/element");
       NodeList nodes = (NodeList)expression.evaluate(document, XPathConstants.NODESET);
       System.out.println("\nNode Name:\t" + nodes.item(0).getNodeName());
       System.out.println("Node Value:\t" + nodes.item(0).getTextContent());
       System.out.println("Attributes: ");
       NamedNodeMap attrs = nodes.item(0).getAttributes();
       for (int i = 0; i < attrs.getLength(); i++){
           Attr attribute = (Attr)attrs.item(i);
           System.out.println(attribute.getName() + " : " + attribute.getValue());
       }
       System.out.print("\nUnregistered Namespace Prefixes: ");
       NamespaceContext context = new DefaultNamespaceContext();
       System.out.println(context.getNamespaceURI("default")); // returns null because it has not been registered

       // Registering namespace
       Map<String, String> prefix2uri = new HashMap<>();
       prefix2uri.put("prefix", "http://example.com/mynamespace");
       context = new SimpleNamespaceContext(prefix2uri);
       System.out.println(context.getNamespaceURI("prefix")); // returns http://example.com/mynamespace

       System.exit(0);
   }

static class SimpleNamespaceContext implements NamespaceContext {
      private final Map<String, String> prefix2uri;

     public SimpleNamespaceContext(final Map<String, String> prefix2uri) {
          if (prefix2uri == null) {
              throw new IllegalArgumentException("Null map");
         }
         this.prefix2uri = Collections.unmodifiableMap(prefix2uri);
      }

   @Override
   public String getNamespaceURI(final String prefix) {
        if (prefix == null) {
            throw new IllegalArgumentException("Null prefix");
        } else if ("default".equals(prefix)) {
            return XMLConstants.NULL_NS_URI;
        }
       return prefix2uri.get(prefix);
    }

     @Override
     public String getPrefix(final String namespaceURI) {
        throw new UnsupportedOperationException();
     }

     @Override
     public Iterator getPrefixes(final String namespaceURI) {
        throw new UnsupportedOperationException();
     }
}
}

